INSERT OR IGNORE INTO camps (id, slug, name, sport, age_min, age_max, start_date, end_date, address, city, state, zip, latitude, longitude, description, price_text, day_or_overnight, skill_level, spots_status, contact_email, contact_phone, website_url, lunch_included, aftercare_available, status, submitted_by_email, submitted_at, reviewed_by, reviewed_at, verified, program_type, registration_deadline, schedule_text) VALUES ('227ea8d3-fead-44b1-a432-8f0b4b5b22c8', 'gig-harbor-day-camp', 'Gig Harbor Day Camp', 'outdoor', 6, 12, '2026-06-22', '2026-08-21', '9905 Peacock Hill Ave NW', 'Gig Harbor', 'WA', '98332', 47.3486056, -122.5891, 'Gig Harbor Day Camp offers a summer of outdoor fun for kids ages 6 to 12. Campers spend their days swimming, hiking, doing arts and crafts, playing field games, and exploring nature on the YMCA property. Weekly themes keep activities fresh, and trained counselors lead small groups so every camper gets attention. Registration is by week, so families can pick the dates that work for their summer schedule.', 'Varies by week', 'day', 'all', 'open', NULL, '253-851-3323', 'https://www.ymcapkc.org/locations/tom-taylor-family-ymca', 0, 0, 'approved', 'jeffthomas@pugetsound.edu', '2026-05-03T21:51:56.293226+00:00', 'jeff (bulk import)', '2026-05-03T21:51:56.293226+00:00', 0, 'camp', NULL, NULL);
INSERT OR IGNORE INTO camps (id, slug, name, sport, age_min, age_max, start_date, end_date, address, city, state, zip, latitude, longitude, description, price_text, day_or_overnight, skill_level, spots_status, contact_email, contact_phone, website_url, lunch_included, aftercare_available, status, submitted_by_email, submitted_at, reviewed_by, reviewed_at, verified, program_type, registration_deadline, schedule_text) VALUES ('52494e56-95b0-4bac-a7f8-399d9fe167b9', 'tacoma-school-recreation-league-basketball', 'Tacoma School Recreation League Basketball', 'basketball', 6, 14, '2026-06-15', '2026-08-22', '3873 South 66th Street', 'Tacoma', 'WA', '98409', 47.1983048, -122.4886581, 'The Tacoma School Recreation League runs a summer basketball season for kids in grades 1 through 8. Teams practice once a week and play games on Saturdays at gyms across Tacoma. The league focuses on fundamentals, sportsmanship, and giving every player meaningful playing time. Coaches are volunteers, and the league welcomes new players regardless of experience.', NULL, 'day', 'all', 'open', 'info@tsrl.org', '253-305-1025', 'https://www.tsrl.org', 0, 0, 'approved', 'jeffthomas@pugetsound.edu', '2026-05-03T21:51:56.293226+00:00', 'jeff (bulk import)', '2026-05-03T21:51:56.293226+00:00', 0, 'league', '2026-06-01', 'Practices weekly with games on Saturdays');
INSERT OR IGNORE INTO camps (id, slug, name, sport, age_min, age_max, start_date, end_date, address, city, state, zip, latitude, longitude, description, price_text, day_or_overnight, skill_level, spots_status, contact_email, contact_phone, website_url, lunch_included, aftercare_available, status, submitted_by_email, submitted_at, reviewed_by, reviewed_at, verified, program_type, registration_deadline, schedule_text) VALUES ('e4a5f704-3bff-4b77-865f-65d305fa8439', 'fablab-education-summer-camps-2026', 'FABLAB Education Summer Camps 2026', 'stem', 7, 14, '2026-06-22', '2026-08-28', '764 S 38th Street', 'Tacoma', 'WA', '98418', 47.2228956, -122.4427573, 'FABLAB Education runs week-long summer camps in Tacoma for kids interested in making, building, and design. Campers rotate through hands-on projects in 3D printing, laser cutting, electronics, robotics, and woodworking. Each week has a theme, and campers take home the projects they build. Camps are led by working makers and educators who guide kids through the design process from sketch to finished piece. Full scholarships available for Tacoma youth via Tacoma Creates.', NULL, 'day', 'all', 'open', 'info@fablabeducation.org', '253-830-2188', 'https://www.fablabeducation.org/program/day-camps/', 0, 0, 'approved', 'jeffthomas@pugetsound.edu', '2026-05-03T21:51:56.293226+00:00', 'jeff (bulk import)', '2026-05-03T21:51:56.293226+00:00', 0, 'camp', NULL, NULL);
INSERT OR IGNORE INTO camps (id, slug, name, sport, age_min, age_max, start_date, end_date, address, city, state, zip, latitude, longitude, description, price_text, day_or_overnight, skill_level, spots_status, contact_email, contact_phone, website_url, lunch_included, aftercare_available, status, submitted_by_email, submitted_at, reviewed_by, reviewed_at, verified, program_type, registration_deadline, schedule_text) VALUES ('6322c011-88ae-4e65-b256-6de8935dda9d', 'sahale-outdoors-nature-camp', 'Sahale Outdoors Nature Camp', 'outdoor', 6, 13, '2026-06-29', '2026-08-21', '3408 70th Avenue East', 'Fife', 'WA', '98424', 47.2259888, -122.3370591, 'Sahale Outdoors runs nature day camps for kids who want to spend their summer outside. Campers learn wilderness skills, identify plants and animals, build forts, cook over a fire, and play group games in the woods. Counselors are trained naturalists who keep groups small and the pace flexible. Campers should come prepared to get muddy and tired in the best possible way. Sessions run from the org base in Fife and at field locations across the south Puget Sound area.', NULL, 'day', 'beginner', 'open', 'hello@sahaleoutdoors.org', NULL, 'https://sahaleoutdoors.org/', 0, 0, 'approved', 'jeffthomas@pugetsound.edu', '2026-05-03T21:51:56.293226+00:00', 'jeff (bulk import)', '2026-05-03T21:51:56.293226+00:00', 0, 'camp', NULL, NULL);
INSERT OR IGNORE INTO camps (id, slug, name, sport, age_min, age_max, start_date, end_date, address, city, state, zip, latitude, longitude, description, price_text, day_or_overnight, skill_level, spots_status, contact_email, contact_phone, website_url, lunch_included, aftercare_available, status, submitted_by_email, submitted_at, reviewed_by, reviewed_at, verified, program_type, registration_deadline, schedule_text) VALUES ('93bf33b1-f130-4084-9185-65d442cf0359', 'shs-cheer-summer-kids-camp', 'SHS Cheer Summer Kids Camp', 'cheer', 5, 12, '2026-07-13', '2026-07-16', '1801 South Stadium Way', 'Tacoma', 'WA', '98405', 47.264577, -122.4457679, 'Stadium High School cheerleaders host a four-day kids cheer camp each summer. Campers learn cheers, chants, jumps, and a short routine that they perform for families on the last day. The camp is led by current Stadium cheerleaders with coaching staff supervision. All skill levels are welcome, and every camper gets a t-shirt and a snack each day.', '$95', 'day', 'all', 'open', 'stadiumcheer@tacoma.k12.wa.us', NULL, 'https://my.peachjar.com/district/3158/flyer/3042055', 0, 0, 'approved', 'jeffthomas@pugetsound.edu', '2026-05-03T21:51:56.293226+00:00', 'jeff (bulk import)', '2026-05-03T21:51:56.293226+00:00', 0, 'camp', NULL, NULL);
INSERT OR IGNORE INTO camps (id, slug, name, sport, age_min, age_max, start_date, end_date, address, city, state, zip, latitude, longitude, description, price_text, day_or_overnight, skill_level, spots_status, contact_email, contact_phone, website_url, lunch_included, aftercare_available, status, submitted_by_email, submitted_at, reviewed_by, reviewed_at, verified, program_type, registration_deadline, schedule_text) VALUES ('7a88d94c-c388-4618-a054-4141d3370321', 'quantum-martial-arts-summer-camp', 'Quantum Martial Arts Summer Camp', 'martial-arts', 5, 13, '2026-06-22', '2026-08-28', '2367 Tacoma Mall Blvd', 'Tacoma', 'WA', '98409', 47.2060742, -122.4639162, 'Quantum Martial Arts runs week-long summer camps that mix karate training with games, crafts, and field trips. Mornings focus on technique, drills, and sparring at age-appropriate levels. Afternoons include team challenges, outdoor play, and weekly themed activities. Campers do not need prior martial arts experience to attend.', '$249 per week', 'day', 'all', 'open', 'info@quantum-ma.com', '253-475-7100', 'https://www.quantum-ma.com/summer-camp', 0, 1, 'approved', 'jeffthomas@pugetsound.edu', '2026-05-03T21:51:56.293226+00:00', 'jeff (bulk import)', '2026-05-03T21:51:56.293226+00:00', 0, 'camp', NULL, NULL);
INSERT OR IGNORE INTO camps (id, slug, name, sport, age_min, age_max, start_date, end_date, address, city, state, zip, latitude, longitude, description, price_text, day_or_overnight, skill_level, spots_status, contact_email, contact_phone, website_url, lunch_included, aftercare_available, status, submitted_by_email, submitted_at, reviewed_by, reviewed_at, verified, program_type, registration_deadline, schedule_text) VALUES ('9e5f5ec4-5251-49f9-a084-c203f10095f6', 'animal-adventures-with-seattle-humane', 'Animal Adventures with Seattle Humane', 'academic', 6, 11, '2026-07-06', '2026-08-14', '13212 SE Eastgate Way', 'Bellevue', 'WA', '98005', 47.5807598, -122.1654236, 'Animal Adventures is a week-long day camp at Seattle Humane where kids spend time with shelter animals and learn about animal care, behavior, and welfare. Campers meet adoptable cats and dogs, hear from staff about veterinary work and shelter operations, and complete crafts and service projects that benefit shelter animals. Each session ends with a small showcase for families.', '$425 per week', 'day', 'all', 'open', 'humane.education@seattlehumane.org', '425-373-5385', 'https://www.seattlehumane.org/programs/youth-programs/summer-camp', 0, 0, 'approved', 'jeffthomas@pugetsound.edu', '2026-05-03T21:51:56.293226+00:00', 'jeff (bulk import)', '2026-05-03T21:51:56.293226+00:00', 0, 'camp', NULL, NULL);
INSERT OR IGNORE INTO camps (id, slug, name, sport, age_min, age_max, start_date, end_date, address, city, state, zip, latitude, longitude, description, price_text, day_or_overnight, skill_level, spots_status, contact_email, contact_phone, website_url, lunch_included, aftercare_available, status, submitted_by_email, submitted_at, reviewed_by, reviewed_at, verified, program_type, registration_deadline, schedule_text) VALUES ('d24a285f-a1ef-4b5c-8cdd-574e668680b9', 'camp-invention-at-marvista-elementary', 'Camp Invention at Marvista Elementary', 'stem', 5, 11, '2026-07-20', '2026-07-24', '12517 Marine View Dr SW', 'Burien', 'WA', '98146', 47.4912108, -122.3629421, 'Camp Invention is a week-long STEM day camp run by the National Inventors Hall of Fame at Marvista Elementary. Campers work in small teams on hands-on challenges that mix engineering, problem solving, and creativity. Activities change each year and include taking apart real devices, building prototypes, and pitching inventions. The program is led by trained local educators.', '$295', 'day', 'all', 'open', NULL, '800-968-4332', 'https://www.invent.org/programs/camp-invention', 0, 0, 'approved', 'jeffthomas@pugetsound.edu', '2026-05-03T21:51:56.293226+00:00', 'jeff (bulk import)', '2026-05-03T21:51:56.293226+00:00', 0, 'camp', NULL, NULL);
INSERT OR IGNORE INTO camps (id, slug, name, sport, age_min, age_max, start_date, end_date, address, city, state, zip, latitude, longitude, description, price_text, day_or_overnight, skill_level, spots_status, contact_email, contact_phone, website_url, lunch_included, aftercare_available, status, submitted_by_email, submitted_at, reviewed_by, reviewed_at, verified, program_type, registration_deadline, schedule_text) VALUES ('54e29ba9-a52e-4f6b-a21a-c03494dcfe97', 'city-of-enumclaw-hornets-volleyball-camp', 'City of Enumclaw Hornets Volleyball Camp', 'volleyball', 9, 14, '2026-07-27', '2026-07-30', '226 Semanski St S', 'Enumclaw', 'WA', '98022', 47.1900223, -122.0083049, 'The City of Enumclaw Parks and Recreation department hosts a four-day youth volleyball camp run by Enumclaw High School coaches and players. Campers work on passing, setting, hitting, and serving with drills appropriate to their grade and experience level. The camp ends with scrimmage play and a small awards moment for each camper. Players should bring water, knee pads, and athletic shoes.', '$85', 'day', 'all', 'open', 'parks@enumclawwa.gov', '360-615-5601', 'https://www.cityofenumclaw.net', 0, 0, 'approved', 'jeffthomas@pugetsound.edu', '2026-05-03T21:51:56.293226+00:00', 'jeff (bulk import)', '2026-05-03T21:51:56.293226+00:00', 0, 'camp', NULL, NULL);
INSERT OR IGNORE INTO camps (id, slug, name, sport, age_min, age_max, start_date, end_date, address, city, state, zip, latitude, longitude, description, price_text, day_or_overnight, skill_level, spots_status, contact_email, contact_phone, website_url, lunch_included, aftercare_available, status, submitted_by_email, submitted_at, reviewed_by, reviewed_at, verified, program_type, registration_deadline, schedule_text) VALUES ('80045ccf-9475-4953-9dd5-3be5cf0f4f65', 'summer-sessions-at-camp-arnold', 'Summer Sessions at Camp Arnold', 'outdoor', 7, 17, '2026-06-21', '2026-08-15', '33712 Webster Rd E', 'Eatonville', 'WA', '98328', NULL, NULL, 'Camp Arnold runs traditional overnight summer camp sessions at its lakeside property near Eatonville. Campers swim, canoe, hike, climb the high ropes course, do crafts, and gather for evening campfires. Sessions run by age group, and counselors live in the cabins with their groups. Some sessions have specialty tracks like horseback riding, paintball, or wakeboarding for older campers.', 'Varies by session', 'overnight', 'all', 'open', 'info@camparnold.org', '360-825-7771', 'https://www.camparnold.org', 0, 0, 'approved', 'jeffthomas@pugetsound.edu', '2026-05-03T21:51:56.293226+00:00', 'jeff (bulk import)', '2026-05-03T21:51:56.293226+00:00', 0, 'camp', NULL, NULL);
INSERT OR IGNORE INTO camps (id, slug, name, sport, age_min, age_max, start_date, end_date, address, city, state, zip, latitude, longitude, description, price_text, day_or_overnight, skill_level, spots_status, contact_email, contact_phone, website_url, lunch_included, aftercare_available, status, submitted_by_email, submitted_at, reviewed_by, reviewed_at, verified, program_type, registration_deadline, schedule_text) VALUES ('299c056a-798c-4b13-ad74-bd325e7a5dc0', 'free-capoeira-camp', 'Free Capoeira Camp', 'martial-arts', 7, 14, '2026-08-03', '2026-08-07', '755 Broadway', 'Tacoma', 'WA', '98402', 47.256083, -122.4405102, 'This free week-long camp at Tacoma Capoeira Center introduces kids to capoeira, the Afro-Brazilian martial art that blends movement, music, and acrobatics. Campers learn basic kicks, dodges, and floor work, plus the songs and instruments that accompany the roda. The camp is taught by trained capoeira instructors and is open to beginners. Comfortable clothes and water are all that is needed.', 'Free', 'day', 'beginner', 'open', NULL, NULL, 'https://tacomacapoeiracenter.com/', 0, 0, 'approved', 'jeffthomas@pugetsound.edu', '2026-05-03T21:51:56.293226+00:00', 'jeff (bulk import)', '2026-05-03T21:51:56.293226+00:00', 0, 'camp', NULL, NULL);
